import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"复活节真菌","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/3.C级/复活节真菌.md","filePath":"4.资源分区/7.物品与装备/3.防具/3.C级/复活节真菌.md"}'),d={name:"4.资源分区/7.物品与装备/3.防具/3.C级/复活节真菌.md"};function _(l,e,i,p,c,h){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"复活节真菌",tabindex:"-1"},[n("复活节真菌 "),a("a",{class:"header-anchor",href:"#复活节真菌","aria-label":'Permalink to "复活节真菌"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调017")])])],-1),o('<h1 id="复活节真菌-1" tabindex="-1">复活节真菌 <a class="header-anchor" href="#复活节真菌-1" aria-label="Permalink to &quot;复活节真菌&quot;">​</a></h1><p>复活节真菌<br> 本质：特异本质<br> 价格：C+1000<br> 分类：盾<br> 体积：3<br> 武器伤害：2L<br> 武器属性：【格挡11】<br> 描述：怎么吃都吃不完的面包，外观看起来像是发霉一样长着绿色的青苔，作为盾牌而言不仅坚固，更有着可食用的优点。</p><p>复活节：持有者获得等同自身耐力附加成功*2点的真菌护甲效果，这些真菌护甲等同于等量的盔甲防御与临时生命，当临时生命被击破时，会在战斗后缓慢的恢复（20分钟1点），你可以使用快速医疗进行恢复这些临时生命。<br> 此外，对抗擒抱检定时，真菌护甲此时每剩余1点未被击毁的临时生命，就会额外提供1点对抗擒抱检定上的力量加值。</p><p>可食用：复活节真菌看起来就是一块长着绿色霉菌的大块面包，携带者看起来也会绿油油的。此外，大块面包可以食用，每食用一次可以使一人饱腹，无视对方的食谱需求。不过，每提供一人的饱腹就会使1点活体真菌当日无法恢复临时生命值。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',6)])])}const f=r(d,[["render",_]]);export{m as __pageData,f as default};
